 9→// KeyFor generates the S3 key for an item's content.
10→// Pattern: {owner_id}/{type}/{item_id}/{filename}
11→func KeyFor(ownerID uuid.UUID, itemType string, itemID uuid.UUID, filename string) string {
12→	return fmt.Sprintf("%s/%s/%s/%s", ownerID, itemType, itemID, filename)
13→}
14→
15→// BookmarkKey returns the key for a bookmark's fetched HTML content.
16→func BookmarkKey(ownerID, itemID uuid.UUID) string {
17→	return KeyFor(ownerID, "bookmarks", itemID, "content.html")
18→}
19→
20→// AudioKey returns the key for a voice note's audio file.
21→func AudioKey(ownerID, itemID uuid.UUID, format string) string {
22→	return KeyFor(ownerID, "voice_notes", itemID, "audio."+format)
23→}
24→
25→// FileKey returns the key for a generic file upload.
26→func FileKey(ownerID, itemID uuid.UUID, filename string) string {
27→	return KeyFor(ownerID, "files", itemID, filename)
28→}
