 44→	if cfg.AccessKey != "" && cfg.SecretKey != "" {
 45→		opts = append(opts, awsconfig.WithCredentialsProvider(
 46→			credentials.NewStaticCredentialsProvider(cfg.AccessKey, cfg.SecretKey, ""),
 47→		))
 48→	}
 49→
 50→	awsCfg, err := awsconfig.LoadDefaultConfig(context.Background(), opts...)
 51→	if err != nil {
 52→		return nil, fmt.Errorf("storage: load aws config: %w", err)
 53→	}
